# ── HELPERS ───────────────────────────────────────────────────────────────────
def clean(text):
    fillers = r'\b(umm?|uhh?|ahh?|like|you know|basically|literally|actually|so|well|right)\b'
    return re.sub(r' +', ' ', re.sub(fillers, '', text, flags=re.IGNORECASE)).strip()

def read_txt(f):  return f.read().decode("utf-8")
def read_pdf(f):
    r = PyPDF2.PdfReader(f)
    return "\n".join(p.extract_text() for p in r.pages if p.extract_text())
def read_docx(f):
    d = Document(f)
    return "\n".join(p.text for p in d.paragraphs if p.text.strip())
def extract_file(f):
    n = f.name.lower()
    if n.endswith(".txt"):  return read_txt(f)
    if n.endswith(".pdf"):  return read_pdf(f)
    if n.endswith(".docx"): return read_docx(f)
    return "❌ Unsupported file type."

def transcribe(uploaded):
    rec = sr.Recognizer()
    suffix = ".wav" if uploaded.name.lower().endswith(".wav") else ".mp3"

    with tempfile.NamedTemporaryFile(delete=False, suffix=suffix) as t:
        t.write(uploaded.read())
        tp = t.name

    wav_path = tp

    if suffix == ".mp3":
        wav_path = tp.replace(".mp3", ".wav")
        try:
            # Try pydub first (uses the paths set above)
            AudioSegment.from_mp3(tp).export(wav_path, format="wav")
        except Exception:
            try:
                AudioSegment.from_file(tp).export(wav_path, format="wav")
            except Exception:
                try:
                    # Direct ffmpeg command with full path
                    ffmpeg_path = shutil.which("ffmpeg") or "C:\\ffmpeg\\bin\\ffmpeg.exe"
                    result = subprocess.run([
                        ffmpeg_path, "-y",
                        "-analyzeduration", "100M",
                        "-probesize", "100M",
                        "-i", tp,
                        "-ar", "16000",
                        "-ac", "1",
                        "-f", "wav",
                        wav_path
                    ], capture_output=True, timeout=60)
                    if result.returncode != 0:
                        os.remove(tp)
                        return "❌ Could not decode MP3. Try converting to WAV at convertio.co"
                except Exception as e:
                    os.remove(tp)
                    return f"❌ Audio conversion failed: {e}"
    try:
        with sr.AudioFile(wav_path) as source:
            rec.adjust_for_ambient_noise(source, duration=0.5)
            audio_data = rec.record(source)
            return rec.recognize_google(audio_data)
    except sr.UnknownValueError:
        return "❌ Could not understand the audio. Ensure clear speech in the recording."
    except sr.RequestError as e:
        return f"❌ Speech recognition error: {e}"
    finally:
        if os.path.exists(tp): os.remove(tp)
        if wav_path != tp and os.path.exists(wav_path): os.remove(wav_path)

def summarize(text, length, tone, fmt):
    lm = {"Short":"2-3 sentences, 3-4 bullet points.","Medium":"3-4 sentences, 5-7 bullets.","Detailed":"Full paragraph, comprehensive bullets."}
    tm = {"Formal":"Professional business language.","Simple":"Plain easy-to-read language."}
    fm = {"Bullet Points":"Use bullet points.","Paragraph":"Use flowing paragraphs."}
    prompt = f"""You are an expert meeting summarizer.
Length: {lm[length]} | Tone: {tm[tone]} | Format: {fm[fmt]}
Avoid repetition. Only important info.

Respond ONLY in this exact format:

SHORT SUMMARY:
[overview]

KEY POINTS:
[key points]

TOPICS DISCUSSED:
[topics]

IMPORTANT POINTS:
[decisions/actions]

ISSUES:
[problems or "None"]

MEETING CONTENT:
{text}"""
    try:
        r = client.models.generate_content(model="gemini-2.5-flash", contents=prompt)
        raw = r.text
        def ex(h, c):
            m = re.search(rf"{h}:\n(.*?)(?=\n[A-Z ]+:|$)", c, re.DOTALL)
            return m.group(1).strip() if m else ""
        ts = datetime.now().strftime("%Y-%m-%d %H:%M")
        ss=ex("SHORT SUMMARY",raw); kp=ex("KEY POINTS",raw)
        td=ex("TOPICS DISCUSSED",raw); ip=ex("IMPORTANT POINTS",raw); iss=ex("ISSUES",raw)
        full = f"SHORT SUMMARY:\n{ss}\n\nKEY POINTS:\n{kp}\n\nTOPICS DISCUSSED:\n{td}\n\nIMPORTANT POINTS:\n{ip}\n\nISSUES:\n{iss}"
        return {"short_summary":ss,"key_points":kp,"topics_discussed":td,"important_points":ip,"issues":iss,"timestamp":ts,"full_text":full}
    except Exception as e:
        st.error(f"❌ Gemini API Error: {e}"); return {}

def summarize_image(image_bytes, mime_type, length, tone, fmt):
    lm = {"Short":"2-3 sentences, 3-4 bullet points.","Medium":"3-4 sentences, 5-7 bullets.","Detailed":"Full paragraph, comprehensive bullets."}
    tm = {"Formal":"Professional business language.","Simple":"Plain easy-to-read language."}
    fm = {"Bullet Points":"Use bullet points.","Paragraph":"Use flowing paragraphs."}
    import base64 as b64mod
    img_b64 = b64mod.b64encode(image_bytes).decode()
    prompt = f"""You are an expert at reading and summarizing handwritten or printed documents from images.
Extract ALL text from this image, then create a structured meeting summary.
Length: {lm[length]} | Tone: {tm[tone]} | Format: {fm[fmt]}

Respond ONLY in this exact format:

SHORT SUMMARY:
[overview]

KEY POINTS:
[key points]

TOPICS DISCUSSED:
[topics]

IMPORTANT POINTS:
[decisions/actions]

ISSUES:
[problems or "None"]"""
    try:
        response = client.models.generate_content(
            model="gemini-2.5-flash",
            contents=[
                {"role":"user","parts":[
                    {"inline_data":{"mime_type":mime_type,"data":img_b64}},
                    {"text":prompt}
                ]}
            ]
        )
        raw = response.text
        def ex(h, c):
            m = re.search(rf"{h}:\n(.*?)(?=\n[A-Z ]+:|$)", c, re.DOTALL)
            return m.group(1).strip() if m else ""
        ts = datetime.now().strftime("%Y-%m-%d %H:%M")
        ss=ex("SHORT SUMMARY",raw); kp=ex("KEY POINTS",raw)
        td=ex("TOPICS DISCUSSED",raw); ip=ex("IMPORTANT POINTS",raw); iss=ex("ISSUES",raw)
        full = f"SHORT SUMMARY:\n{ss}\n\nKEY POINTS:\n{kp}\n\nTOPICS DISCUSSED:\n{td}\n\nIMPORTANT POINTS:\n{ip}\n\nISSUES:\n{iss}"
        return {"short_summary":ss,"key_points":kp,"topics_discussed":td,"important_points":ip,"issues":iss,"timestamp":ts,"full_text":full}
    except Exception as e:
        st.error(f"❌ Gemini Vision Error: {e}"); return {}

def make_pdf(results):
    buf = BytesIO()
    doc = SimpleDocTemplate(buf,pagesize=A4,rightMargin=2*cm,leftMargin=2*cm,topMargin=2*cm,bottomMargin=2*cm)
    styles = getSampleStyleSheet()
    ts = ParagraphStyle('T',parent=styles['Title'],fontSize=20,textColor=colors.HexColor("#2196d4"),spaceAfter=20)
    hs = ParagraphStyle('H',parent=styles['Heading2'],fontSize=13,textColor=colors.HexColor("#0a1a22"),spaceBefore=14,spaceAfter=6)
    bs = ParagraphStyle('B',parent=styles['Normal'],fontSize=10,leading=16,spaceAfter=8)
    story = [Paragraph("ConvoLog — AI Meeting Summary",ts),Spacer(1,0.3*cm)]
    for heading,key in [("Short Summary","short_summary"),("Key Points","key_points"),("Topics Discussed","topics_discussed"),("Important Points","important_points"),("Issues","issues")]:
        content = results.get(key,"")
        if content:
            story.append(Paragraph(heading,hs))
            for line in content.split("\n"):
                if line.strip(): story.append(Paragraph(line.strip(),bs))
            story.append(Spacer(1,0.2*cm))
    doc.build(story)
    return buf.getvalue()

def render_results(results, msg, key_prefix):
    c = C()
    st.markdown(f'<div class="success-box">✅ {msg}</div>', unsafe_allow_html=True)
    for label, key in [("SHORT SUMMARY","short_summary"),("KEY POINTS","key_points")]:
        st.markdown(f'<div class="sec-label">{label}</div>', unsafe_allow_html=True)
        st.markdown(f'<div class="output-box">{results.get(key,"")}</div>', unsafe_allow_html=True)
    ca, cb = st.columns(2)
    with ca:
        st.markdown('<div class="sec-label">TOPICS DISCUSSED</div>', unsafe_allow_html=True)
        st.markdown(f'<div class="output-box">{results.get("topics_discussed","")}</div>', unsafe_allow_html=True)
    with cb:
        st.markdown('<div class="sec-label">IMPORTANT POINTS</div>', unsafe_allow_html=True)
        st.markdown(f'<div class="output-box">{results.get("important_points","")}</div>', unsafe_allow_html=True)
    st.markdown('<div class="sec-label">ISSUES</div>', unsafe_allow_html=True)
    st.markdown(f'<div class="output-box">{results.get("issues") or "None reported."}</div>', unsafe_allow_html=True)
    st.markdown("<br>", unsafe_allow_html=True)
    dc, pc = st.columns(2)
    with dc:
        pdf_bytes = make_pdf(results)
        ts_str = datetime.now().strftime("%Y%m%d_%H%M%S")
        fname = f"convolog_{ts_str}.pdf"
        clicked = st.download_button("⬇️ Download as PDF",data=pdf_bytes,file_name=fname,mime="application/pdf",key=f"dl_{key_prefix}_{ts_str}")
        if clicked:
            st.session_state.downloads.append({"label":fname,"ts":results.get("timestamp",""),"data":results.get("full_text","")})
    with pc:
        if st.button("📌 Pin this Summary", key=f"pin_{key_prefix}_{results.get('timestamp','')}"):
            entry = {"label":f"Summary — {results.get('timestamp','')}","ts":results.get("timestamp",""),"data":results.get("full_text","")}
            if entry["label"] not in [p["label"] for p in st.session_state.pinned]:
                st.session_state.pinned.append(entry); st.success("📌 Pinned!")
            else: st.info("Already pinned.")
    st.markdown('<div class="sec-label">COPY FULL SUMMARY</div>', unsafe_allow_html=True)
    st.text_area("",value=results.get("full_text",""),height=140,key=f"cp_{key_prefix}_{results.get('timestamp','')}")

def render_sidebar():
    c = C()
    with st.sidebar:
        if st.session_state.logged_in:
            name = st.session_state.user_email.split('@')[0].title()
            st.markdown(f"""<div class="profile-area">
                <div class="avatar">{ICONS['user']}</div>
                <div><div class="pname">{name}</div><div class="pemail">{st.session_state.user_email}</div></div>
            </div>""", unsafe_allow_html=True)
            if st.button("🚪 Sign Out",key="signout"):
                st.session_state.logged_in=False; st.session_state.user_email=""; st.rerun()
        else:
            st.markdown(f"""<div class="profile-area">
                <div class="avatar">{ICONS['user']}</div>
                <div><div class="pname">Your Account</div><div class="pemail">Sign in to save history</div></div>
            </div>""", unsafe_allow_html=True)
            if st.button("Sign In / Register",key="signin_btn"):
                st.session_state.show_login=not st.session_state.show_login; st.rerun()
        if st.session_state.show_login and not st.session_state.logged_in:
            with st.expander("Account",expanded=True):
                email=st.text_input("Email",placeholder="you@email.com",key="l_e")
                pw=st.text_input("Password",type="password",key="l_p")
                c1,c2=st.columns(2)
                with c1:
                    if st.button("Login",key="do_l") and email and pw:
                        st.session_state.logged_in=True; st.session_state.user_email=email
                        st.session_state.show_login=False; st.rerun()
                with c2:
                    if st.button("Register",key="do_r") and email and pw:
                        st.session_state.logged_in=True; st.session_state.user_email=email
                        st.session_state.show_login=False; st.rerun()
        st.markdown("<hr>",unsafe_allow_html=True)

        if st.session_state.sidebar_view:
            view = st.session_state.sidebar_view
            if st.button("← Back",key="back_btn"):
                st.session_state.sidebar_view=None; st.rerun()
            titles={"history":"🕐 History","downloads":"⬇️ Recently Downloaded","pinned":"📌 Pinned"}
            st.markdown(f'<div style="font-family:Sora,sans-serif;font-size:.74rem;font-weight:700;letter-spacing:.12em;text-transform:uppercase;color:rgba(126,184,212,.8);padding:6px 0 8px;">{titles[view]}</div>',unsafe_allow_html=True)
            arr = {"history":st.session_state.history,"downloads":st.session_state.downloads,"pinned":st.session_state.pinned}[view]
            if not arr:
                st.markdown('<div class="empty-st">Nothing here yet.</div>',unsafe_allow_html=True)
            else:
                for i,item in enumerate(reversed(arr)):
                    label=item.get("label","") if isinstance(item,dict) else str(item)
                    ts=item.get("ts","") if isinstance(item,dict) else ""
                    data=item.get("data","") if isinstance(item,dict) else ""
                    with st.expander(f"{label}"):
                        st.markdown(f'<div style="font-size:.7rem;color:rgba(126,184,212,.7);margin-bottom:0px;">{ts}</div>',unsafe_allow_html=True)
                        if data: st.text_area("",value=data,height=200,key=f"sv_{view}_{i}")
            return

        st.markdown(f'<div class="nav-clickable">{ICONS["search"]} &nbsp; Search</div>',unsafe_allow_html=True)
        sq=st.text_input("",placeholder="Search history...",key="sq",label_visibility="collapsed")
        st.markdown("<hr>",unsafe_allow_html=True)
        if st.button("⬇️  Recently Downloaded",key="nav_dl"):
            st.session_state.sidebar_view="downloads"; st.rerun()
        st.markdown("<hr>",unsafe_allow_html=True)
        if st.button("🕐  History",key="nav_hist"):
            st.session_state.sidebar_view="history"; st.rerun()
        st.markdown("<hr>",unsafe_allow_html=True)
        if st.button("📌  Pinned Conversations",key="nav_pin"):
            st.session_state.sidebar_view="pinned"; st.rerun()
        st.markdown("<hr>",unsafe_allow_html=True)
        icon=ICONS["moon"] if st.session_state.dark_mode else ICONS["sun"]
        label="Dark Mode ON" if st.session_state.dark_mode else "Light Mode ON"
        st.markdown(f'<div class="mode-row">{icon} &nbsp; {label}</div>',unsafe_allow_html=True)
        if st.button("Toggle Theme",key="tog"):
            st.session_state.dark_mode=not st.session_state.dark_mode; st.rerun()

def opts_row(prefix):
    """Render options row — returns (length, tone, fmt, summarize_clicked, close_clicked)"""
    o0,o1,o2,o3,o4,o5 = st.columns([0.7,1.8,1.8,1.8,1.2,1.0])
    with o0: st.markdown('<div class="opts-label">OPTIONS</div>',unsafe_allow_html=True)
    with o1: sl=st.selectbox("",["Short","Medium","Detailed"],key=f"sl_{prefix}",label_visibility="collapsed")
    with o2: tn=st.selectbox("",["Formal","Simple"],key=f"tn_{prefix}",label_visibility="collapsed")
    with o3: fm=st.selectbox("",["Bullet Points","Paragraph"],key=f"fm_{prefix}",label_visibility="collapsed")
    with o4: sb=st.button("Summarize",key=f"sb_{prefix}")
    with o5: cb=st.button("Close",key=f"cb_{prefix}")
    return sl,tn,fm,sb,cb

def main():
    sub_img = inject_css()
    render_sidebar()
    c = C()

    st.markdown(f'<div class="top-logo">{sub_img}</div>',unsafe_allow_html=True)

    tab1,tab2,tab3,tab4 = st.tabs(["TEXT INPUT","FILE UPLOAD","AUDIO UPLOAD","IMAGE UPLOAD"])


    # ════════════════════════════════════════
    # TAB 1 — TEXT INPUT
    # ════════════════════════════════════════
    with tab1:
        st.markdown("### Input Meeting Conversation")

        if "text_key" not in st.session_state:
            st.session_state.text_key = 0

        # ── VOICE RECORDER COMPONENT ──────────────────────────────────────
        recorder_html = f"""
        <style>
        @keyframes dotPulse {{
            0%,100%{{opacity:1;transform:scale(1);}}
            50%{{opacity:.3;transform:scale(.8);}}
        }}
        @keyframes btnPulse {{
            0%{{box-shadow:0 0 0 0 rgba(192,57,43,.5);}}
            70%{{box-shadow:0 0 0 14px rgba(192,57,43,0);}}
            100%{{box-shadow:0 0 0 0 rgba(192,57,43,0);}}
        }}
        #recBtn{{
            display:flex;align-items:center;gap:8px;
            background:#1a7abf;color:#fff;border:none;border-radius:8px;
            padding:.48rem 1.4rem;font-family:'DM Sans',sans-serif;
            font-weight:600;font-size:.9rem;cursor:pointer;
            transition:all .2s;white-space:nowrap;min-width:180px;justify-content:center;
        }}
        #recBtn.recording{{
            background:#c0392b!important;
            animation:btnPulse 1.4s ease infinite;
        }}
        #recBtn:hover{{filter:brightness(1.15);}}
        #recDot{{
            width:9px;height:9px;border-radius:50%;background:#ff4444;
            display:none;animation:dotPulse 1s ease infinite;flex-shrink:0;
        }}
        #recBtn.recording #recDot{{display:block;}}
        #waveWrap{{
            display:none;
            background:{c['bg_input']};
            border:1.5px solid rgba(30,111,168,.55);
            border-radius:10px;padding:12px 16px;margin-top:10px;
        }}
        #waveLabel{{
            font-size:.73rem;color:{c['text_sub']};margin-bottom:7px;
            font-family:'Sora',sans-serif;letter-spacing:.08em;text-transform:uppercase;
        }}
        #waveCanvas{{width:100%;height:65px;display:block;border-radius:6px;}}
        #transcriptBox{{
            display:none;
            background:{c['bg_input']};
            border:1.5px solid rgba(33,150,212,.45);
            border-radius:10px;padding:10px 14px;margin-top:8px;
            font-size:.85rem;line-height:1.6;min-height:40px;
        }}
        #addBtn{{
            display:none;
            background:transparent;color:#2196d4;
            border:1.5px solid #2196d4;border-radius:7px;
            padding:.36rem 1.2rem;font-family:'DM Sans',sans-serif;
            font-weight:600;font-size:.83rem;cursor:pointer;margin-top:8px;
            transition:background .18s;
        }}
        #addBtn:hover{{background:rgba(33,150,212,.12);}}
        #recStatus{{font-size:.8rem;color:{c['text_sub']};margin-left:12px;}}
        </style>

        <div style="margin-bottom:10px;">
            <div style="display:flex;align-items:center;">
                <button id="recBtn" onclick="toggleRec()">
                    <div id="recDot"></div>
                    <svg width="15" height="15" viewBox="0 0 24 24" fill="none"
                        stroke="white" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
                        <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/>
                        <path d="M19 10v2a7 7 0 0 1-14 0v-2"/>
                        <line x1="12" y1="19" x2="12" y2="23"/>
                        <line x1="8" y1="23" x2="16" y2="23"/>
                    </svg>
                    <span id="recLabel">🎙️ Start Recording</span>
                </button>
                <span id="recStatus"></span>
            </div>

            <div id="waveWrap">
                <div id="waveLabel">🔴 Recording — Speak now</div>
                <canvas id="waveCanvas" width="800" height="65"></canvas>
            </div>

            <div id="transcriptBox">
                <span id="interimTxt" style="color:{c['text_sub']};font-style:italic;"></span>
                <span id="finalTxt" style="color:{c['text']};"></span>
            </div>

            <button id="addBtn" onclick="addToNotes()">✅ Add to Notes</button>
        </div>

        <script>
        let recognition = null;
        let isRecording = false;
        let finalTranscript = '';
        let mediaStream = null;
        let audioCtx = null;
        let analyser = null;
        let animFrame = null;

        function toggleRec() {{
            isRecording ? stopRecording() : startRecording();
        }}

        function startRecording() {{
            const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
            if (!SR) {{ alert('Use Chrome or Edge for voice recording.'); return; }}

            recognition = new SR();
            recognition.continuous = true;
            recognition.interimResults = true;
            recognition.lang = 'en-US';

            recognition.onstart = () => {{
                isRecording = true;
                setUI(true);
                startWaveform();
            }};

            recognition.onresult = (e) => {{
                let interim = '';
                for (let i = e.resultIndex; i < e.results.length; i++) {{
                    if (e.results[i].isFinal) {{
                        finalTranscript += e.results[i][0].transcript + ' ';
                    }} else {{
                        interim += e.results[i][0].transcript;
                    }}
                }}
                document.getElementById('finalTxt').textContent = finalTranscript;
                document.getElementById('interimTxt').textContent = interim;
                document.getElementById('transcriptBox').style.display = 'block';
                if (finalTranscript.trim()) {{
                    document.getElementById('addBtn').style.display = 'inline-block';
                }}
            }};

            recognition.onerror = (e) => {{
                if (e.error !== 'no-speech') {{
                    document.getElementById('recStatus').textContent = '❌ ' + e.error;
                    stopRecording();
                }}
            }};

            recognition.onend = () => {{
                if (isRecording) {{
                    try {{ recognition.start(); }} catch(e) {{}}
                }}
            }};

            navigator.mediaDevices.getUserMedia({{ audio: true }})
                .then(stream => {{
                    mediaStream = stream;
                    audioCtx = new (window.AudioContext || window.webkitAudioContext)();
                    analyser = audioCtx.createAnalyser();
                    analyser.fftSize = 512;
                    audioCtx.createMediaStreamSource(stream).connect(analyser);
                    drawWave();
                }}).catch(() => {{}});

            recognition.start();
        }}

        function stopRecording() {{
            isRecording = false;
            if (recognition) {{ try {{ recognition.stop(); }} catch(e) {{}} recognition = null; }}
            if (mediaStream) {{ mediaStream.getTracks().forEach(t => t.stop()); mediaStream = null; }}
            if (audioCtx) {{ audioCtx.close(); audioCtx = null; }}
            if (animFrame) {{ cancelAnimationFrame(animFrame); animFrame = null; }}
            setUI(false);
            if (finalTranscript.trim()) {{
                document.getElementById('recStatus').textContent = '✅ Done — click Add to Notes';
            }}
        }}

        function setUI(recording) {{
            const btn = document.getElementById('recBtn');
            const lbl = document.getElementById('recLabel');
            const wave = document.getElementById('waveWrap');
            if (recording) {{
                btn.classList.add('recording');
                lbl.textContent = '⏹ Stop Recording';
                wave.style.display = 'block';
                document.getElementById('recStatus').textContent = '';
            }} else {{
                btn.classList.remove('recording');
                lbl.textContent = '🎙️ Start Recording';
                wave.style.display = 'none';
            }}
        }}

        function drawWave() {{
            if (!analyser) return;
            const canvas = document.getElementById('waveCanvas');
            const ctx = canvas.getContext('2d');
            const W = canvas.width, H = canvas.height;
            const bufLen = analyser.frequencyBinCount;
            const data = new Uint8Array(bufLen);

            function render() {{
                animFrame = requestAnimationFrame(render);
                analyser.getByteTimeDomainData(data);
                ctx.clearRect(0, 0, W, H);

                const grad = ctx.createLinearGradient(0, 0, W, 0);
                grad.addColorStop(0,   'rgba(33,150,212,0.2)');
                grad.addColorStop(0.5, 'rgba(33,150,212,1)');
                grad.addColorStop(1,   'rgba(33,150,212,0.2)');

                ctx.lineWidth = 2.5;
                ctx.strokeStyle = grad;
                ctx.beginPath();
                const slice = W / bufLen;
                let x = 0;
                for (let i = 0; i < bufLen; i++) {{
                    const y = (data[i] / 128.0) * (H / 2);
                    i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
                    x += slice;
                }}
                ctx.lineTo(W, H / 2);
                ctx.stroke();

                const maxVal = Math.max(...data);
                if (maxVal > 140) {{
                    ctx.lineWidth = 8;
                    ctx.strokeStyle = 'rgba(33,150,212,0.18)';
                    ctx.stroke();
                }}
            }}
            render();
        }}

        function addToNotes() {{
            const text = finalTranscript.trim();
            if (!text) return;
            const textareas = window.parent.document.querySelectorAll('textarea');
            for (let ta of textareas) {{
                if (ta.placeholder && ta.placeholder.includes('Paste')) {{
                    const setter = Object.getOwnPropertyDescriptor(
                        window.HTMLTextAreaElement.prototype, 'value').set;
                    setter.call(ta, (ta.value ? ta.value + ' ' : '') + text);
                    ta.dispatchEvent(new Event('input', {{ bubbles: true }}));
                    break;
                }}
            }}
            document.getElementById('addBtn').textContent = '✅ Added!';
            setTimeout(() => {{
                document.getElementById('addBtn').textContent = '✅ Add to Notes';
            }}, 2000);
            finalTranscript = '';
            document.getElementById('finalTxt').textContent = '';
            document.getElementById('interimTxt').textContent = '';
        }}
        </script>
        """
        components.html(recorder_html, height=100)

        # Text area
        text_input = st.text_area(
            "",
            value="",
            height=200,
            placeholder="Paste your meeting notes here...",
            key=f"ta_main_{st.session_state.text_key}"
        )

        o0,o1,o2,o3,o4,o5 = st.columns([0.7,1.8,1.8,1.8,1.3,1.1])
        with o0: st.markdown('<div class="opts-label">OPTIONS</div>', unsafe_allow_html=True)
        with o1: sl=st.selectbox("",["Short","Medium","Detailed"],key="sl1",label_visibility="collapsed")
        with o2: tn=st.selectbox("",["Formal","Simple"],key="tn1",label_visibility="collapsed")
        with o3: fm=st.selectbox("",["Bullet Points","Paragraph"],key="fm1",label_visibility="collapsed")
        with o4: sb=st.button("Summarize",key="sb1")
        with o5: cb=st.button("Clear Note",key="cb1")

        if cb:
            st.session_state.text_key += 1
            st.session_state.results = None
            st.rerun()

        if sb:
            content = text_input.strip()
            if not content:
                st.warning("⚠️ Please enter meeting content first.")
            else:
                with st.spinner("🤖 AI is analyzing your meeting..."):
                    res = summarize(clean(content), sl, tn, fm)
                if res:
                    st.session_state.results = res
                    st.session_state.history.append({
                        "label": f"Text — {res['timestamp']}",
                        "ts": res["timestamp"],
                        "data": res["full_text"]
                    })

        if st.session_state.results:
            st.markdown("---")
            render_results(st.session_state.results, "Your Meeting Notes Summarized Successfully!", "text")

    # ════════════════════════════════════════
    # TAB 2 — FILE UPLOAD
    # ════════════════════════════════════════
    with tab2:
        st.markdown("### Upload Your Meeting Document")
        uf=st.file_uploader("Drag and Drop — Limit 200MB • TXT, PDF, DOCX",type=["txt","pdf","docx"],key="fu")
        file_text=""
        if uf:
            kb=round(len(uf.getvalue())/1024,1)
            st.markdown(f'<div style="font-size:.82rem;color:{c["text_sub"]};margin:6px 0;">📄 {uf.name} &nbsp;·&nbsp; {kb} KB</div>',unsafe_allow_html=True)
            with st.spinner("Reading file..."):
                file_text=extract_file(uf)
            with st.expander("▼ Preview Extracted File"):
                st.text(file_text[:2000]+("..." if len(file_text)>2000 else ""))
            sl,tn,fm,fs,fc=opts_row("file")
            if fc:
                st.session_state.file_results=None; st.rerun()
            if fs:
                if not file_text.strip(): st.warning("⚠️ Could not extract text.")
                else:
                    with st.spinner("🤖 Analyzing file..."):
                        res=summarize(clean(file_text),sl,tn,fm)
                    if res:
                        st.session_state.file_results=res
                        st.session_state.history.append({"label":f"File: {uf.name} — {res['timestamp']}","ts":res["timestamp"],"data":res["full_text"]})
            if st.session_state.file_results:
                st.markdown("---")
                render_results(st.session_state.file_results,"Your Meeting File Summarized Successfully!","file")
        else:
            st.markdown(f'<div style="color:{c["text_sub"]};font-size:.87rem;padding:.8rem 0;">Upload a .txt, .pdf, or .docx file to get started.</div>',unsafe_allow_html=True)

    # ════════════════════════════════════════
    # TAB 3 — AUDIO UPLOAD
    # ════════════════════════════════════════
    with tab3:
        st.markdown("### Upload Meeting Audio")
        ua=st.file_uploader("Drag and Drop — Limit 200MB • MP3, WAV",type=["mp3","wav"],key="au")
        audio_text=""
        if ua:
            kb=round(len(ua.getvalue())/1024,1)
            st.markdown(f'<div style="font-size:.82rem;color:{c["text_sub"]};margin:6px 0;">🎵 {ua.name} &nbsp;·&nbsp; {kb} KB</div>',unsafe_allow_html=True)
            with st.expander("▶️ Play Audio File"):
                mime="audio/wav" if ua.name.lower().endswith(".wav") else "audio/mpeg"
                st.audio(ua.getvalue(),format=mime)
            with st.spinner("🎙️ Transcribing audio..."):
                ua.seek(0); audio_text=transcribe(ua)
            if audio_text.startswith("❌"):
                st.error(audio_text); audio_text=""
            else:
                with st.expander("📝 Preview Transcription"):
                    st.text(audio_text[:2000])
            if audio_text:
                sl,tn,fm,as_,ac=opts_row("audio")
                if ac:
                    st.session_state.audio_results=None; st.rerun()
                if as_:
                    with st.spinner("🤖 Analyzing audio..."):
                        res=summarize(clean(audio_text),sl,tn,fm)
                    if res:
                        st.session_state.audio_results=res
                        st.session_state.history.append({"label":f"Audio: {ua.name} — {res['timestamp']}","ts":res["timestamp"],"data":res["full_text"]})
                if st.session_state.audio_results:
                    st.markdown("---")
                    render_results(st.session_state.audio_results,"Your Audio Summarized Successfully!","audio")
        else:
            st.markdown(f'<div style="color:{c["text_sub"]};font-size:.87rem;padding:.8rem 0;">Upload an .mp3 or .wav file to get started.</div>',unsafe_allow_html=True)

    # ════════════════════════════════════════
    # TAB 4 — IMAGE UPLOAD
    # ════════════════════════════════════════
    with tab4:
        st.markdown("### Upload or Capture Document Image")
        st.markdown(f'<div style="font-size:.85rem;color:{c["text_sub"]};margin-bottom:12px;">📸 Upload a scanned document, handwritten notes, or take a photo with your camera. AI will read and summarize it.</div>',unsafe_allow_html=True)

        # Camera capture (works on mobile)
        cam_col, upload_col = st.columns([1,1])
        with cam_col:
            st.markdown(f'<div style="font-size:.82rem;color:{c["text_sub"]};margin-bottom:6px;">📷 Take a Photo (mobile/webcam)</div>',unsafe_allow_html=True)
            camera_img = st.camera_input("",key="cam_input",label_visibility="collapsed")

        with upload_col:
            st.markdown(f'<div style="font-size:.82rem;color:{c["text_sub"]};margin-bottom:6px;">🖼️ Upload Image File</div>',unsafe_allow_html=True)
            uploaded_img = st.file_uploader("Upload image",type=["jpg","jpeg","png","webp","bmp"],key="img_up",label_visibility="collapsed")

        # Determine which image to use
        img_bytes = None
        mime_type = "image/jpeg"
        img_source = None

        if camera_img is not None:
            img_bytes = camera_img.getvalue()
            mime_type = "image/jpeg"
            img_source = "camera"
        elif uploaded_img is not None:
            img_bytes = uploaded_img.getvalue()
            ext = uploaded_img.name.lower().split(".")[-1]
            mime_map = {"jpg":"image/jpeg","jpeg":"image/jpeg","png":"image/png","webp":"image/webp","bmp":"image/bmp"}
            mime_type = mime_map.get(ext,"image/jpeg")
            img_source = uploaded_img.name

        if img_bytes:
            kb = round(len(img_bytes)/1024,1)
            st.markdown(f'<div style="font-size:.82rem;color:{c["text_sub"]};margin:6px 0;">{"📷 Camera capture" if img_source=="camera" else f"🖼️ {img_source}"} &nbsp;·&nbsp; {kb} KB</div>',unsafe_allow_html=True)

            # Show preview
            with st.expander("▼ Preview Image"):
                st.image(img_bytes, use_container_width=True)

            # Options
            sl,tn,fm,is_,ic=opts_row("img")
            if ic:
                st.session_state.image_results=None; st.rerun()
            if is_:
                with st.spinner("🤖 AI is reading your image..."):
                    res=summarize_image(img_bytes,mime_type,sl,tn,fm)
                if res:
                    st.session_state.image_results=res
                    label = "Camera photo" if img_source=="camera" else img_source
                    st.session_state.history.append({"label":f"Image: {label} — {res['timestamp']}","ts":res["timestamp"],"data":res["full_text"]})

            if st.session_state.image_results:
                st.markdown("---")
                render_results(st.session_state.image_results,"Your Image Summarized Successfully!","img")
        else:
            st.markdown(f'<div style="color:{c["text_sub"]};font-size:.87rem;padding:.8rem 0;">Use the camera (great on mobile!) or upload an image file of your notes/document.</div>',unsafe_allow_html=True)

if __name__ == "__main__":
    main()
